          const wispRing = new THREE.Mesh(new THREE.TorusGeometry(wR, 0.022, 8, 24), wisp);
          wispRing.position.y = wY;
          wispRing.rotation.x = (wi % 3) * 0.55;
          wispRing.rotation.z = wi * 0.42;
          sbHover.add(wispRing);
