          const bar = new THREE.Mesh(new THREE.BoxGeometry(0.072, 0.012, 0.015), featherBarMat);
          bar.position.set((tf - 3.5) * 0.045, 0.004, -0.07 - Math.abs(tf - 3.5) * 0.025);
