            hawkLegGroup.add(toePad);
            const talon = new THREE.Mesh(new THREE.ConeGeometry(0.012, 0.09, 10), talonMat);
            talon.position.set((tc - 1) * 0.028, -0.37, 0.05 + tc * 0.01);
